% Polynome d'interpolation avec differences divisees% Donneesx = [ -55 -25 5 35 65 ];y = [ -3.25 -3.2 -3.02 -3.32 -3.1 ];% Coefficients des differences diviseesd = dividif ( x , y )% Polynome de Newtonn = length(x);z = linspace ( x(1) , x(end) , 100 );w = 1;p = w* d(1,1);for i=1:n-1  w = w .* (z - x(i));  p = p + d(i+1,i+1).*w;end % Affichagefigure; plot(z,p,x,y,'o'); grid on;